definition.script:
pipeline {
    agent {
        label "linux_aarch64"
    }
    environment {
        ARTIFACTORY_CREDS = credentials('openjdk-artifactory')
    }
    stages {
        stage("Checkout Infrastructure Repository") {
            steps {
                checkout changelog: false, poll: false, scm: [$class: 'GitSCM', branches: [[name: '*/master']], extensions: [[$class: 'RelativeTargetDirectory', relativeTargetDir: 'SapMachine-infrastructure']], userRemoteConfigs: [[credentialsId: 'SapMachine-github', url: 'https://github.com/SAP/SapMachine-infrastructure.git']]]
            }
        }
        stage("Checkout SapMachine Repository") {
            agent {
                dockerfile {
                    dir "SapMachine-infrastructure/devkits/dockerfiles/arm64"
                    reuseNode true
                    label "linux_aarch64"
                }
            }
            steps {
                sh '''#!/bin/bash
                    set -ex
                    git init SapMachine && cd SapMachine
                    git remote add origin $GIT_REPOSITORY
                    git fetch origin $GIT_REF
                    git checkout --detach FETCH_HEAD
                '''
            }
        }

        stage("Build") {
            agent {
                dockerfile {
                    dir "SapMachine-infrastructure/devkits/dockerfiles/arm64"
                    reuseNode true
                    label "linux_aarch64"
                }
            }
            steps {
                sh "cd SapMachine/make/devkit && make BASE_OS=${BASE_OS} BASE_OS_VERSION=${BASE_OS_VERSION} GCC_VER=${GCC_VERSION} tars"
            }
        }
        stage("Upload Artifactory") {
            steps {
                // Upload devkit archive
                sh 'curl -sSf -u $ARTIFACTORY_CREDS -X PUT -T SapMachine/build/devkit/result/*.tar.gz https://common.repositories.cloud.sap/artifactory/sapmachine-mvn/io/sapmachine/build/devkit/linux-aarch64/devkit-fedora-gcc/${BASE_OS_VERSION}-${GCC_VERSION}/devkit-fedora-gcc-${BASE_OS_VERSION}-${GCC_VERSION}.tar.gz'
            }
        }
    }
    post {
        always {
            cleanWs()
        }
    }
}
